var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……그나저나 주시윤 선배를 찾을 방법은 있어?","JPN":"……ところでアキヤマ先輩を探す方法はあるの？","ENG":"So… You got a plan for how to find Shiyoon?","TWN":"……話說回來，你有想好要怎麼找周時雲前輩嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아카데미 학생들이 도와 주더라도 이 넓은 곳을 전부 뒤지고 다니는 건 무리야.","JPN":"アカデミーの生徒たちが\\n手伝ってくれるとしても、こんな広い場所をすべて探し回るのは無理だよ。","ENG":"Even with all this help, we won't be able to search this entire area.","TWN":"就算學院的學生一起幫忙找，但茫茫人海中是要怎麼找？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……장담은 못하겠지만, 가능성은 있어.","JPN":"……断言はできないけど、可能性はある。","ENG":"I can't guarantee it… but there is a way.","TWN":"雖然我也不太確定這個方法是不是有用……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 칼, 예전에 주시윤 선배의 피를 흡수한 적이 있거든.","JPN":"この剣、以前アキヤマ先輩の血を吸収したことがあるの。","ENG":"This sword absorbed some of his blood before.","TWN":"這把劍之前有吸收過周時雲前輩的血。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"피를 흡수했다고? 칼이?","JPN":"血を吸収したの？　剣が？","ENG":"Absorbed his blood? This sword?","TWN":"吸血？劍會吸血？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 선배의 피에 녹아 있는 클리포트 인자로 칼을 깨우기 위해서라고 했어.","JPN":"うん。先輩の血に溶けているクリフォト・ファクターで剣を起こすためだと言ってた。","ENG":"Yeah. It was to awaken the sword with the Qliphoth Factor in his blood.","TWN":"嗯，因為要利用溶在前輩血裡的卡巴拉因子來喚醒劍。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"직후에 곧바로 방출해 버리긴 했지만……","JPN":"その直後にすぐ放出してしまったけど……","ENG":"Although I had to release it right away…","TWN":"原本是打算喚醒後就要排出的，但是……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 한 번 각인된 이상 비슷한 종류의 힘이 어느 방향에 있는지 느낄 수 있어.","JPN":"でも、一度刻印された以上、似たような力がどの方向にあるのか感じられるんだ。","ENG":"But once it's been imprinted, the sword can sense where a similar power might be.","TWN":"不過既然已經刻印過一次，應該可以感應到類似的力量在哪個方向。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"신기한 칼이네……? 그런 게 가능하다고?","JPN":"不思議な剣だね……そんなこともできるの？","ENG":"How fascinating… You can actually do that with a sword?","TWN":"這是什麼神奇的劍……還有這種事？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 말 듣고 나니까 정말 늑대 같은데?","JPN":"その話を聞くと本当に狼みたいだね。","ENG":"That really makes you sound like a wolf.","TWN":"聽完這些話覺得還真的有點像狼呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"늑대?","JPN":"狼？","ENG":"A wolf?","TWN":"狼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"응. 한 번 물어뜯은 사냥감은 절대 놓치지 않는 늑대.","JPN":"うん、一度狙った獲物は絶対逃さない狼。","ENG":"Yeah. You know, a wolf that never lets her prey go once she's caught the scent.","TWN":"嗯，一旦咬住獵物就絕對不會鬆口的狼。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"별거 아냐. 아까 그 여자가 널 저주받은 늑대라고 불렀잖아.","JPN":"いや、さっきあの女に呪われた狼と呼ばれたでしょ。","ENG":"Oh, it's nothing really. That lady called you the Cursed Wolf earlier, anyway.","TWN":"沒什麼啦，剛才那女人不是叫你受詛咒的狼嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그런데 그 칼, 네 언니가 가지고 있던 거라고 하지 않았어?","JPN":"ところでその剣、あなたのお姉さんが持っていたものって言ってなかった？","ENG":"By the way, didn't that sword belong to your sister?","TWN":"不過你不是說那把劍原本在你姊姊那嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"처음엔 총 안에 칼이 들어 있는지도 모르더니 잘도 그런 기능이 있다는 걸 알아챘네.","JPN":"最初は銃の中に剣が入っていることすら\\nわからなかったのに、よくそんな機能があることに気づいたね。","ENG":"You didn't even know there was a blade in the gun before. How'd you find out about this imprint thing?","TWN":"一開始連槍裡面有劍都不知道，竟然能發現這把劍有這種用途！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"집에서 매뉴얼이라도 찾은 거야?","JPN":"家でマニュアルでも見つけたの？","ENG":"You find a manual or something?","TWN":"是在家裡找到使用說明書嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 아니고…….","JPN":"いや、それが……","ENG":"Not quite…","TWN":"不是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다이브 실전 훈련에서 4종 침식체와 싸웠을 때였어.","JPN":"ダイブ実戦訓練で第4種侵食体と戦った時だったんだけど。","ENG":"It was when I fought the Category 4 during dive training.","TWN":"是在躍入實戰訓練中和4類侵蝕體戰鬥時，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 때, 이상한…… 내 것이 아닌 기억들이 머릿속에 들어왔어.","JPN":"あの時、変な……自分のものではない記憶が頭の中に入ってきたの。","ENG":"Some strange memories… ones that didn't belong to me found their way into my head.","TWN":"那時很奇怪……我腦中突然出現一些不屬於我的記憶，"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 칼의 이름이 울브즈베인이라는 것과, 몇 가지 기능들.","JPN":"この剣の名前がウルブズベインということと、いくつかの機能。","ENG":"I learned that the sword's name is Wolvesbane and a few of its special features.","TWN":"包括這把劍的名字叫作狼之災禍和一些功能，"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 검술, 전투 이론 같은 지식들도.","JPN":"そして剣術、戦闘理論のような知識も。","ENG":"And also how to fight with it, like stances and combat theories.","TWN":"還有像是劍術、戰鬥理論之類的知識，"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 예전부터 알고 있었던 것처럼 익숙한데, 아무리 생각해도 내 기억 같지가 않아.","JPN":"昔から知っていたかのように馴染んでるけど、いくら考えても私の記憶ではないの。","ENG":"They all feel familiar, as if I've always known about them, but there's no way these are my own memories.","TWN":"好像我以前就知道這些似的，但又不屬於我的記憶。"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마치…… 머릿속에 또다른 내가 살고 있는 것처럼.","JPN":"まるで……頭の中にもう一人の私がいるみたい。","ENG":"It's as if… someone else is living in my head.","TWN":"感覺就像……我腦中住著另一個我一樣。"},"stage":{"bg":"MAINSTREAM_6100019","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"언니는……. 이 칼을 어디서 얻은 걸까?","JPN":"姉さんは……この剣をどこで手に入れたんだろう？","ENG":"I wonder… Where could my sister have gotten this sword?","TWN":"姊姊……是在哪裡得到這把劍的呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……뭐, 복잡한 건 나중에 생각하자.","JPN":"……まあ、難しいことはあとで考えよう。","ENG":"Well… Let's think about the complicated stuff later.","TWN":"……嗯，好複雜，之後再想吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그래서 어느 쪽이야?","JPN":"それで、どっちなの？","ENG":"So which way should we go?","TWN":"現在要往哪裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"칼이 이끄는 방향은……. 저쪽이야.","JPN":"剣が導く方向は……あっちだ。","ENG":"According to the sword… that way.","TWN":"劍指引的方向是……那裡！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아. 정말인지 기분 탓인지는 가서 확인해 보면 알겠지.","JPN":"よし。あってるか気のせいなのかは直接確かめるしかない！","ENG":"Great. I guess we'll find out if it can really do what you said or if it's all in your head.","TWN":"好！我們就來確認一下到底是真是假吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};